// === Công thức hoa hồng 5 bậc Happy Home — CHÍNH XÁC theo agent-engine ===
const body = $input.first().json.body;
const dealAmount = Number(body.deal_amount);
const TY = 1e9; // 1 tỷ VND

// Tổng pool hoa hồng dự án = 4% giá trị deal.
const pool = dealAmount * 0.04;

// Bậc lũy tiến frontline tính trên monthly volume SAU khi cộng deal này.
const volumeAfter = Number(body.sale_monthly_volume_before || 0) + dealAmount;
function frontlinePct(v) {
  if (v < 5 * TY) return 50;
  if (v < 10 * TY) return 55;
  if (v < 15 * TY) return 60;
  if (v < 20 * TY) return 62;
  return 65;
}
const flPct = frontlinePct(volumeAfter);

// 5 bậc: company 20% / director 10% / manager 5% / leader 15% / frontline lũy tiến.
const tierDefs = [
  { role: 'company',   label: 'Ekip công ty',   pct: 20,    name: 'Ekip công ty', chat_id: '',                              user_id: '' },
  { role: 'director',  label: 'Giám đốc',       pct: 10,    name: body.director_name || 'Giám đốc',   chat_id: body.director_telegram_chat_id || '', user_id: body.director_id || '' },
  { role: 'manager',   label: 'Trưởng phòng',   pct: 5,     name: body.manager_name || 'Trưởng phòng', chat_id: body.manager_telegram_chat_id || '', user_id: body.manager_id || '' },
  { role: 'leader',    label: 'Sale Leader',    pct: 15,    name: body.leader_name || 'Sale Leader',   chat_id: body.leader_telegram_chat_id || '',  user_id: body.leader_id || '' },
  { role: 'frontline', label: 'Sale Frontline', pct: flPct, name: body.sale_name || 'Sale',           chat_id: body.sale_telegram_chat_id || '',    user_id: body.sale_id || '' },
];

function fmt(n) { return Math.round(n).toLocaleString('vi-VN'); }

const tiers = tierDefs.map(t => ({
  role: t.role,
  user_id: t.user_id,
  pct: t.pct,
  amount: Math.round(pool * t.pct / 100),
}));

// Chỉ gửi Telegram cho người đã liên kết chat_id.
const recipients = tierDefs.filter(t => t.chat_id).map(t => {
  const amount = Math.round(pool * t.pct / 100);
  const message = t.role === 'frontline'
    ? `🎉 Bạn đã chốt deal ${fmt(dealAmount)}đ — hoa hồng *${fmt(amount)}đ* (bậc ${t.pct}%)!`
    : `💰 Deal mới: ${fmt(dealAmount)}đ\nHoa hồng ${t.label} của bạn: *${fmt(amount)}đ*`;
  return { role: t.role, name: t.name, chat_id: t.chat_id, pct: t.pct, amount, message, deal_id: body.deal_id };
});

const distribution = {
  deal_id: body.deal_id,
  deal_amount: dealAmount,
  commission_pool: Math.round(pool),
  sale_id: body.sale_id,
  sale_monthly_volume_after: volumeAfter,
  frontline_tier_pct: flPct,
  tiers,
  recipients,
};

return [{ json: distribution }];
